var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"이것 봐라. 관리국 놈들이 덤벙거릴 때가 다 있네.","JPN":"あっれー？　管理局の奴らもミスする時があるんだ。","ENG":"Well, would you look at that. So even the Administration messes up sometimes.","TWN":"看看這個。原來管理局的那些傢伙也有慌張的時候啊。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"앨버트, 기뻐해! 내가 월척을 건졌어!","JPN":"アルバート、喜べ！　大魚を釣り上げたぞ！","ENG":"Great news, Albert! I think I've caught a big one!","TWN":"高興吧，阿爾伯特！我這裡有人上鉤了！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"기뻐하기엔 이른 것 같은데. 네 기준으로 따지면 송사리도 월척이라고 호들갑이잖아.","JPN":"喜ぶにはまだ早いと思うけどね。あなたっていつも大袈裟なんだから。","ENG":"I think it's too soon to celebrate. To you, even a minnow seems like a big catch.","TWN":"你高興得也太早了吧。釣到這種小魚對你來說就是收穫，值得這樣大聲嚷嚷了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그렇게 인심이 후해서 해커라고 할 수 있겠냐.","JPN":"そんなんでハッカーの仕事がつとまるの？","ENG":"Your low standard of success puts your hacker name to shame.","TWN":"這麼老實能自稱是駭客喔。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"어허, 왜 이래. 해커가 아니라 정보상이라고 부르기로 했을 텐데?","JPN":"おい、何だって？　ハッカーじゃなくて情報屋って呼ぶことにしたじゃないか。","ENG":"Hey, come on, now. Didn't we agree to use the term \\"information merchant\\" instead of hacker?","TWN":"吼唷，幹嘛啦，我們不是說好不叫駭客改叫情報商了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"그리고 정보상의 일은 옆집 할머니 잔소리도 그럴싸한 정보로 포장하는 거라고.","JPN":"それに、情報屋の仕事ってのは、隣のおばあちゃんの小言もそれっぽい情報に見せかけることなんだよ。","ENG":"And a good information merchant can take the next door granny's nagging and make it sound important.","TWN":"還有，情報商的工作，就算是隔壁老奶奶的嘮叨，也得包裝成有模有樣的情報。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"자기계발 세미나인지 뭔지 갔다 오더니 또 이상한 물이 들었구만......","JPN":"自己啓発セミナーなんか行って来てから、また変なことに気移りしちゃって……","ENG":"That self-improvement seminar really did a number on you, didn't it?","TWN":"看來去過那個什麼自我啟發的研討會後，這傢伙又變得怪怪的了……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"어디 한 번 봐 봐. 돈 될 만한 정보인지는 내가 판단할 테니까.","JPN":"一回見せてよ。金になりそうな情報かどうか私が判断するから。","ENG":"Let me take a look. I'll be the judge of whether it's worth any money.","TWN":"我來看看吧，我會判斷這個情報值不值錢的。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"보고 놀라지나 마. 이번에 일어났던 리플레이서 사태를 조사한 내용이야.","JPN":"見て驚くなよ。今回起きたリプレイサー事件について調べた内容だ。","ENG":"Brace yourself. It's about the investigations on the recent Replacer incident.","TWN":"看了可別吃驚喔，我調查了最近的克隆集團事件。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"오호라...... 정부 인사 중에도 협력자가 잔뜩 있었네. 이거 한탕 할 수 있겠는데.","JPN":"へえ……政府関係者の中にも協力者がいっぱいいたんだ。これ、一儲けできそうだね。","ENG":"Ooooh... They had a bunch of collaborators within the government, too. I think we've hit the jackpot.","TWN":"喔喔……政府人士中也有很多合作者呢。看來這次可以大幹一場了。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"그런데 어디서 구했어?","JPN":"ところで、どこで手に入れたの？","ENG":"Where did you find this anyway?","TWN":"不過這些情報你是從哪裡弄來的？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"관리국 재난 대책 기구의 전산망이야. 이런 걸 가지고 있으면 잘 보관해 둬야지.","JPN":"管理局災害対策機構のネットワークだよ。これほどの情報ならもっと厳重に保管しないと。","ENG":"The network of the Administration's disaster relief organization. I figured I'd hang on to stuff like this.","TWN":"從管理局災難對策機構的網路那邊弄到的。有這種東西可得好好保管才行呢。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"관리국? 거길 뚫었다고?! 이번엔 정말 대단한데!","JPN":"管理局？　あそこに侵入したの！？　本当にすごい！","ENG":"The Administration? You managed to get through them?! Wow, that's really impressive!","TWN":"管理局？你突破了那裡的安全系統？！這次真的很厲害啊！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이거 잘만 하면 떼돈을 벌겠어. 잘했어, 매버릭.","JPN":"これ、うまくいくと莫大なお金が入るかも。よくやった、マーベリック。","ENG":"We could make a fortune out of this if we play it right. Good job, Maverick.","TWN":"順利的話說不定可以撈一票了。幹得漂亮，麥伯利。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"......매버릭? 왜 말이 없어? 감자칩 다 떨어졌어?","JPN":"……マーベリック？　急に黙り込んでどうした？　ポテトチップス切れた？","ENG":"Maverick? Cat got your tongue? Are you out of potato chips?","TWN":"……麥伯利？怎麼不說話了？薯片吃完了？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"저, 저기...... 손님이 온 것 같은데......?","JPN":"お、おい……お客さんが来てるようだけど……？","ENG":"U-um... I think we've got company...","TWN":"那，那個……好像來客人了啊……？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"손님이라니, 여기 무슨 손님이 온다고...... 히익?!!","JPN":"お客さんって、こんなところにお客さんが来るはずない……ヒィーッ！","ENG":"What company? Nobody ever comes here— Eeek?!!","TWN":"什麼客人啊，這種地方哪會有什麼客人……咿？！！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_001010","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네가 매버릭인가?","JPN":"君がマーベリックか？","ENG":"Are you Maverick?","TWN":"你就是麥伯利嗎？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AIRBORNE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};